import styled, { keyframes } from "styled-components";
import { getColors } from "../../Styles/colors";
import { GrooveProps } from "./types";

const slideRight = keyframes`
  from {
    left: 0;
  }
  to {
    left: 17rem;
  }
`;

export const Container = styled.div`
  width: 100%;
  height: 35rem;
  background-color: ${(props) => getColors(props.theme).accent};
  position: relative;
`;

export const VinylRecord = styled.div`
  height: 35rem;
  width: 35rem;
  border-radius: 300px;
  background-color: black;
  position: absolute;
  top: 0;
  display: flex;
  justify-content: center;
  align-items: center;

  animation: ${slideRight} 3s ease forwards;
`;

export const VinylRecordMiddle = styled.div`
  height: 10rem;
  width: 10rem;
  border-radius: 50%;
  background-color: white;
`;

export const Sleeve = styled.img`
  height: 35rem;
  width: 35rem;
  border-radius: 2%;
`;

const Circle = styled.div<GrooveProps>`
  width: ${({ diameter }) => diameter}px;
  height: ${({ diameter }) => diameter}px;
  border-radius: 50%;
  background-color: ${({ color }) => color};
  position: absolute;
`;
